commands.cmd:
LC_ALL=C awk -v sf=9 '
  { total++; if ($sf ~ /^5/) e++ }
  END {
    if (total == 0) { rate = "0.00" }
    else { rate = sprintf("%.2f", (e / total) * 100) }
    printf "{\"total_requests\":%d,\"error_5xx_count\":%d,\"error_rate_pct\":%s}", total, e, rate
  }
' /var/log/nginx/access.log
